#!/usr/bin/env bash
set -euo pipefail
#shellcheck disable=1091
source "$SCRIPT_ROOT/data/shared/local_env.sh"
#shellcheck disable=2016,2001
find "${1-"$WORK_LOG_DIR"}" -follow -iname '*.md' -print0|xargs -0 sed -sne '/^\s*[^* ]/{H;$!d};/^*/{${x;/^*/x}};x;/^*/{;s/\n\s*/ /g;s/[^0-9(]*//;/^$/be;:b;s/(\([^)]*\))\([^(]*\)(/\2(\1/g;tb;s/\(([^)]*)\)\(.*\)/\2 \1/;s/[^0-9(]*\([0-9]\+\)\s*:\s*\([0-9]\+\)\s*-\s*\([0-9]\+\)\s*:\s*\([0-9]\+\)[^0-9(]*/+@\1:\2@\3:\4\n/g;s/\([0-9]\+\)\s*min\(utes\)\?/\1m/g;s/1h/60m /g;:l;s/([^0-9]*\([0-9]\+\)/-@00:00@\1min 00:00\n(/;tl;s/(.*//g;s/\n$//;/^[^+-]/M{s/[+-]@.*\n\?//gM;w/dev/stderr' -e 'q1};p;:e;N;$!be;d;};'|while IFS=@ read -r S A B;do echo "$S$(($(date +%s -d"$B")-$(date +%s -d"$A")))";done|tr -d '\n'|sed 's/+-/+(60*60*24)-/g;s/^+//;s/$/\n/'|bc|cat "${1-"$WORK_LOG_DIR"}"/hours+holidays+vacation.txt -|sed '/^\s*$/d;/^\s*;.*/d;/^#/{bm;:a;s/\(\n[^*\n]*\*\)\([^\n]\+$\)/ *\2\1\2/;:m;N;/\n[^#]/be;ba;:e;s/\(#[^*]*\*[- 0-9]*\)\n\([^ ]*\).*/\1 * tomorrow $(date -d"tomorrow" +%u|sed "s,[67],8day-\&,;s,^.$,0,")day\n@\2/;p;d};$!s/\([^ ]*\).*/@\1/;$s/^/+/'|sed '/#\s*\([0-9]\+\)[^0-9]*\([-0-9]\+\)\s*.\s*\(.*\)/s,,printf " -$((\1*60*60/5*(($(date -d"\3 -$(date -d"\3" +%u)day1day" +%s)+12*60*60-$(date -d"\2 -$(date -d"\2" +%u)day1day" +%s))/(7*24*60*60)*5-$(date -d"\2" +%u)+$(date -d"\3" +%u))))+",;/^@\(.\)\(.*\)/s,,printf " -(0\1(\2*60*60))",;/^+\(.*\)/s//echo "+(\1)"/'|while IFS= read -r L;do eval "$L";done|bc|sed 's/.*/&s to h/'|xargs qalc|cut -d= -f2||echo|sed -ne 's/^/\x1B[F\x1B[2KInvalid format!\n/;w/dev/stderr' -e 'q1'
